/**
 * Legacy greedy planner that mirrors classic QueryJoinOptimizer heuristic ordering.
 */
public final class LegacyGreedyPlanner implements JoinOrderPlanner {

	@Override
	public String name() {
		return "legacy-greedy";
	}

	@Override
	public List<JoinOrderCandidate> generatePlans(JoinRegion region, JoinOptimizationContext ctx) {
		List<TupleExpr> joinArgs = new ArrayList<>(region.getAtoms());
		if (joinArgs.isEmpty()) {
			return List.of();
		}

		Map<TupleExpr, Double> cardinalityMap = Collections.emptyMap();
		Map<TupleExpr, List<Var>> varsMap = new HashMap<>();

		for (TupleExpr tupleExpr : joinArgs) {
			double cardinality = ctx.getStats().getCardinality(tupleExpr);

			tupleExpr.setResultSizeEstimate(Math.max(cardinality, tupleExpr.getResultSizeEstimate()));
			if (!hasCachedCardinality(tupleExpr)) {
				if (cardinalityMap.isEmpty()) {
					cardinalityMap = new HashMap<>();
				}
				cardinalityMap.put(tupleExpr, cardinality);
			}
			if (tupleExpr instanceof ZeroLengthPath) {
				varsMap.put(tupleExpr, ((ZeroLengthPath) tupleExpr).getVarList());
			} else {
				varsMap.put(tupleExpr, getStatementPatternVars(tupleExpr));
			}
		}

		Map<Var, Integer> varFreqMap = new HashMap<>((varsMap.size() + 1) * 2);
		for (List<Var> varList : varsMap.values()) {
			fillVarFreqMap(varList, varFreqMap);
		}

		double currentHighestCost = 1.0d;
		Set<String> boundVars = new HashSet<>(region.getOuterBoundVars());
		ArrayDeque<TupleExpr> orderedJoinArgs = new ArrayDeque<>(joinArgs.size());
		while (!joinArgs.isEmpty()) {
			TupleExpr tupleExpr = selectNextTupleExpr(joinArgs, cardinalityMap, varsMap, varFreqMap, boundVars,
					currentHighestCost);
			currentHighestCost = Math.max(currentHighestCost, tupleExpr.getCostEstimate());
			joinArgs.remove(tupleExpr);
			orderedJoinArgs.addLast(tupleExpr);
			boundVars.addAll(tupleExpr.getBindingNames());
		}

		List<TupleExpr> ordered = new ArrayList<>(orderedJoinArgs);
		return List.of(JoinOrderCandidate.of(name(), ordered, region.getAtoms()));
	}

	private TupleExpr selectNextTupleExpr(List<TupleExpr> expressions, Map<TupleExpr, Double> cardinalityMap,
			Map<TupleExpr, List<Var>> varsMap, Map<Var, Integer> varFreqMap, Set<String> boundVars,
			double currentHighestCost) {
		if (expressions.size() == 1) {
			TupleExpr tupleExpr = expressions.getFirst();
			if (tupleExpr.getCostEstimate() < 0) {
				tupleExpr.setCostEstimate(
						getTupleExprCost(tupleExpr, cardinalityMap, varsMap, varFreqMap, boundVars,
								currentHighestCost));
			}
			return tupleExpr;
		}

		TupleExpr result = null;
		double lowestCost = Double.POSITIVE_INFINITY;

		for (TupleExpr tupleExpr : expressions) {
			double cost = getTupleExprCost(tupleExpr, cardinalityMap, varsMap, varFreqMap, boundVars,
					currentHighestCost);
			if (cost < lowestCost || result == null) {
				lowestCost = cost;
				result = tupleExpr;
				if (cost == 0.0d) {
					break;
				}
			}
		}

		assert result != null;
		result.setCostEstimate(lowestCost);
		return result;
	}

	private double getTupleExprCost(TupleExpr tupleExpr, Map<TupleExpr, Double> cardinalityMap,
			Map<TupleExpr, List<Var>> varsMap, Map<Var, Integer> varFreqMap, Set<String> boundVars,
			double currentHighestCost) {
		if (tupleExpr instanceof BindingSetAssignment) {
			Set<Var> varsUsedInOtherExpressions = varFreqMap.keySet();
			for (String assuredBindingName : tupleExpr.getAssuredBindingNames()) {
				if (varsUsedInOtherExpressions.contains(Var.of(assuredBindingName))) {
					return 0.0d;
				}
			}
		}

		double cost;
		if (hasCachedCardinality(tupleExpr)) {
			cost = ((AbstractQueryModelNode) tupleExpr).getCardinality();
		} else {
			cost = cardinalityMap.get(tupleExpr);
		}

		cost += 5.0d;
		List<Var> vars = varsMap.get(tupleExpr);
		List<Var> unboundVars = getUnboundVars(vars, boundVars);
		int constantVars = countConstantVars(vars);
		int nonConstantVarCount = vars.size() - constantVars;

		if (nonConstantVarCount > 0) {
			int boundVarCount = nonConstantVarCount - unboundVars.size();
			if (boundVarCount == 0) {
				cost = cost * currentHighestCost;
			} else {
				double exp = (double) unboundVars.size() / nonConstantVarCount;
				cost = Math.pow(cost, exp);
			}
		}

		if (unboundVars.isEmpty()) {
			if (nonConstantVarCount > 0) {
				cost /= nonConstantVarCount;
			}
		} else {
			int foreignVarFreq = getForeignVarFreq(unboundVars, varFreqMap);
			if (foreignVarFreq > 0) {
				cost /= 1 + foreignVarFreq;
			}
		}

		return cost;
	}

	private List<Var> getUnboundVars(List<Var> vars, Set<String> boundVars) {
		int size = vars.size();
		if (size == 0) {
			return List.of();
		}
		if (size == 1) {
			Var var = vars.getFirst();
			if (!var.hasValue() && var.getName() != null && !boundVars.contains(var.getName())) {
				return List.of(var);
			}
			return List.of();
		}

		List<Var> ret = null;
		for (Var var : vars) {
			if (!var.hasValue() && var.getName() != null && !boundVars.contains(var.getName())) {
				if (ret == null) {
					ret = List.of(var);
				} else {
					if (ret.size() == 1) {
						ret = new ArrayList<>(ret);
					}
					ret.add(var);
				}
			}
		}
		return ret != null ? ret : Collections.emptyList();
	}

	private int getForeignVarFreq(List<Var> ownUnboundVars, Map<Var, Integer> varFreqMap) {
		if (ownUnboundVars.isEmpty()) {
			return 0;
		}
		if (ownUnboundVars.size() == 1) {
			return varFreqMap.get(ownUnboundVars.getFirst()) - 1;
		}

		int result = -ownUnboundVars.size();
		for (Var var : new HashSet<>(ownUnboundVars)) {
			result += varFreqMap.get(var);
		}
		return result;
	}

	private int countConstantVars(List<Var> vars) {
		int size = 0;
		for (Var var : vars) {
			if (var.hasValue()) {
				size++;
			}
		}
		return size;
	}

	private void fillVarFreqMap(List<Var> varList, Map<Var, Integer> varFreqMap) {
		if (varList.isEmpty()) {
			return;
		}
		for (Var var : varList) {
			varFreqMap.compute(var, (k, v) -> v == null ? 1 : v + 1);
		}
	}

	private List<Var> getStatementPatternVars(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern) {
			return ((StatementPattern) tupleExpr).getVarList();
		}
		if (tupleExpr instanceof BindingSetAssignment) {
			return List.of();
		}
		return new StatementPatternVarCollector(tupleExpr).getVars();
	}

	private static boolean hasCachedCardinality(TupleExpr tupleExpr) {
		return tupleExpr instanceof AbstractQueryModelNode
				&& ((AbstractQueryModelNode) tupleExpr).isCardinalitySet();
	}

	private static final class StatementPatternVarCollector extends StatementPatternVisitor {
		private final TupleExpr tupleExpr;
		private List<Var> vars;

		private StatementPatternVarCollector(TupleExpr tupleExpr) {
			this.tupleExpr = tupleExpr;
		}

		@Override
		protected void accept(StatementPattern node) {
			if (vars == null) {
				vars = new ArrayList<>(node.getVarList());
			} else {
				vars.addAll(node.getVarList());
			}
		}

		private List<Var> getVars() {
			if (vars == null) {
				try {
					tupleExpr.visit(this);
				} catch (Exception e) {
					if (e instanceof InterruptedException) {
						Thread.currentThread().interrupt();
					}
					throw new IllegalStateException(e);
				}
				if (vars == null) {
					vars = Collections.emptyList();
				}
			}
			return vars;
		}
	}
}
